if(!customElements.get('lib-message')){class LibMessage extends HTMLElement{static get observedAttributes(){return['type','closable','auto-dismiss','icon','compact','details']}
constructor(){super();this._autoDismissTimer=null;this._rendered=!1;this._originalContent=''}
connectedCallback(){if(!this._rendered){if(this.hasAttribute('static')){this._rendered=!0;this._setupAutoDismiss();return}
if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',()=>this._initRender(),{once:!0})}else{requestAnimationFrame(()=>this._initRender())}}else{this._setupAutoDismiss()}}
_initRender(){if(this._rendered)return;this._originalContent=this.innerHTML;this.render();this._rendered=!0;this._setupAutoDismiss()}
disconnectedCallback(){this._clearAutoDismiss()}
attributeChangedCallback(name,oldValue,newValue){if(oldValue===newValue)return;if(this._rendered){if(name==='type'||name==='icon'||name==='compact'||name==='closable'){this.render()}
if(name==='auto-dismiss'){this._setupAutoDismiss()}}}
_getType(){return this.getAttribute('type')||'info'}
_isClosable(){return this.hasAttribute('closable')}
_showIcon(){return this.getAttribute('icon')!=='false'}
_isCompact(){return this.hasAttribute('compact')}
_canCopy(){if(this.getAttribute('copy')==='false')return!1;if(this._getType()==='error'){return!0}
return(typeof window.CMA_IS_ADMIN!=='undefined'&&window.CMA_IS_ADMIN===!0)||(typeof window.CMA_IS_DEVELOPER!=='undefined'&&window.CMA_IS_DEVELOPER===!0)}
_getIcon(type){const icons={success:'lnr-checkmark-circle',error:'lnr-cross-circle',warning:'lnr-warning',info:'lnr-question-circle'};const iconClass=icons[type]||icons.info;return `<span class="lnr ${iconClass}"></span>`}
_getDetails(){return this.getAttribute('details')||''}
render(){const type=this._getType();const closable=this._isClosable();const showIcon=this._showIcon();const compact=this._isCompact();const details=this._getDetails();const canCopy=this._canCopy();const classes=['lib-message',`lib-message--${type}`];if(compact)classes.push('lib-message--compact');if(details)classes.push('lib-message--has-details');let detailsHtml='';if(details){detailsHtml=`
                <details class="lib-message__details">
                    <summary>Details</summary>
                    <pre class="lib-message__details-content">${this._escapeHtml(details)}</pre>
                </details>
            `}
const copyButtonHtml=canCopy?`
            <button class="lib-message__copy" type="button" aria-label="Kopiëren" title="Kopieer naar klembord">
                <span class="lnr lnr-copy"></span>
            </button>
        `:'';this.innerHTML=`
            <div class="${classes.join(' ')}" role="alert">
                ${showIcon ? `<span class="lib-message__icon">${this._getIcon(type)}</span>` : ''}
                <div class="lib-message__content">
                    ${this._originalContent}
                    ${detailsHtml}
                </div>
                <div class="lib-message__actions">
                    ${copyButtonHtml}
                    ${closable ? `<button class="lib-message__close" type="button" aria-label="Sluiten"><span class="lnr lnr-cross"></span></button>` : ''}
                </div>
            </div>
        `;if(canCopy){const copyBtn=this.querySelector('.lib-message__copy');if(copyBtn){copyBtn.addEventListener('click',()=>this._copyToClipboard())}}
if(closable){const closeBtn=this.querySelector('.lib-message__close');if(closeBtn){closeBtn.addEventListener('click',()=>this.close())}}}
async _copyToClipboard(){const contentEl=this.querySelector('.lib-message__content');const details=this._getDetails();let textToCopy=contentEl?contentEl.textContent.trim():this._originalContent;if(details){textToCopy+='\n\nDetails:\n'+details}
try{await navigator.clipboard.writeText(textToCopy);const copyBtn=this.querySelector('.lib-message__copy');if(copyBtn){const originalHtml=copyBtn.innerHTML;copyBtn.innerHTML=`<span class="lnr lnr-checkmark-circle"></span>`;copyBtn.classList.add('lib-message__copy--success');setTimeout(()=>{copyBtn.innerHTML=originalHtml;copyBtn.classList.remove('lib-message__copy--success')},1500)}}catch(err){console.error('Failed to copy:',err)}}
_escapeHtml(text){const div=document.createElement('div');div.textContent=text;return div.innerHTML}
_setupAutoDismiss(){this._clearAutoDismiss();const duration=parseInt(this.getAttribute('auto-dismiss'));if(duration>0){this._autoDismissTimer=setTimeout(()=>this.close(),duration)}}
_clearAutoDismiss(){if(this._autoDismissTimer){clearTimeout(this._autoDismissTimer);this._autoDismissTimer=null}}
close(){this._clearAutoDismiss();const messageEl=this.querySelector('.lib-message');if(messageEl){messageEl.classList.add('lib-message--removing');messageEl.addEventListener('animationend',()=>{this.dispatchEvent(new CustomEvent('lib-message-close',{bubbles:!0}));this.remove()},{once:!0})}else{this.remove()}}
show(message,type){if(message!==undefined){this._originalContent=String(message);if(type){this.setAttribute('type',type)}
this._rendered=!0;this.render()}
this.hidden=!1}}
customElements.define('lib-message',LibMessage)}
window.libMessage={create:function(message,options={}){const{type='info',closable=!0,autoDismiss=0,icon=!0,compact=!1,container=document.body,position='prepend'}=options;const el=document.createElement('lib-message');el.setAttribute('type',type);if(closable)el.setAttribute('closable','');if(autoDismiss>0)el.setAttribute('auto-dismiss',autoDismiss.toString());if(!icon)el.setAttribute('icon','false');if(compact)el.setAttribute('compact','');el.textContent=message;if(position==='prepend'){container.prepend(el)}else{container.appendChild(el)}
return el},info:function(message,options={}){return this.create(message,{...options,type:'info'})},success:function(message,options={}){return this.create(message,{...options,type:'success'})},warning:function(message,options={}){return this.create(message,{...options,type:'warning'})},error:function(message,options={}){return this.create(message,{...options,type:'error'})},clearAll:function(container=document.body){container.querySelectorAll('lib-message').forEach(el=>el.close())}};window.Lib_ToonTopNotificatie=function(text,fixed,type){if(!type){type='info'}
const existingTop=document.getElementById('lib-top-notification');if(existingTop)existingTop.remove();let container=document.getElementById('lib-top-notification-container');if(!container){container=document.createElement('div');container.id='lib-top-notification-container';container.style.cssText='position:fixed;top:16px;left:50%;transform:translateX(-50%);z-index:10001;max-width:600px;width:calc(100% - 32px);';document.body.appendChild(container)}
const el=document.createElement('lib-message');el.id='lib-top-notification';el.setAttribute('type',type);el.setAttribute('closable','');if(!fixed){el.setAttribute('auto-dismiss','3000')}
el.textContent=text;container.appendChild(el);return el}
